{
    version     2.0;
    format      ascii;
    class       dictionary;
    object      blockMeshDict;
}
// * * * * * * * * * * * * * * * * * * * * * * * * * * * * * * * * * * * * * //

scale   0.001;

vertices
(
    (-50,  25,  25)  // 0 - inlet top-left
    (-50,  25, -25)  // 1 - inlet bottom-left
    (-50, -25, -25)  // 2 - outlet bottom-left
    (-50, -25,  25)  // 3 - outlet top-left
    (  25,  25,  25)  // 4 - bend corner right/top
    (  25,  25, -25)  // 5 - bend corner right/bottom
    (  25, -25, -25)  // 6 - outlet bottom-right
    (  25, -25,  25)  // 7 - outlet top-right
);

blocks
(
    hex (0 1 2 3 4 5 6 7) (20 20 20) simpleGrading (1 1 1)
);

boundary
(
    inlet
    {
        type patch;
        faces ((0 1 2 3))
    }
    outlet
    {
        type patch;
        faces ((4 5 6 7))
    }
    walls
    {
        type wall;
        faces (
            (0 3 7 4)
            (1 2 6 5)
            (0 1 5 4)
            (3 2 6 7)
            (0 1 2 3)
            (4 5 6 7)
        )
    }
);

